diff --git a/packages/svelte/src/internal/client/reactivity/batch.js b/packages/svelte/src/internal/client/reactivity/batch.js
index 1d08b5c3d..9202b6563 100644
--- a/packages/svelte/src/internal/client/reactivity/batch.js
+++ b/packages/svelte/src/internal/client/reactivity/batch.js
@@ -463,6 +463,15 @@ export function flushSync(fn) {
 		flush_tasks();

 		if (queued_root_effects.length === 0) {
+			// Check if there are any pending effects that need to be processed
+			// This fixes the issue where effects scheduled during flushSync
+			// might not be processed properly
+			if (batch.#effects.length > 0 || batch.#render_effects.length > 0 || batch.#block_effects.length > 0) {
+				// Process any remaining effects before returning
+				batch.flush_effects();
+				continue;
+			}
+
 			if (batch === current_batch) {
 				batch.flush();
 			}
