import { flushSync } from 'svelte';
import { describe, it, expect } from 'vitest';

/**
 * Test case to reproduce the bug described in the issue:
 * flushSync() not properly executing $effect runes during testing
 */
describe('Rune effects with flushSync', () => {
  it('should execute $effect rune synchronously when flushSync is called', () => {
    // Simulate the logger.svelte.test.js from the reproduction repo
    const log = [];
    let count = 0;

    // Create an effect that logs the count value
    // This simulates the $effect rune behavior
    const effect = () => {
      log.push(count);
    };

    // Manually trigger the effect (simulating mount)
    effect();

    // Count should be 0 initially
    expect(log).toEqual([0]);

    // Clear the log for the test
    log.length = 0;

    // Update count and expect effect to run immediately with flushSync
    count = 1;
    flushSync();

    // The effect should have been executed by flushSync
    expect(log).toEqual([1]);
  });

  it('should handle multiple effect updates without infinite loop', () => {
    const log = [];
    let count = 0;

    const effect = () => {
      if (count === 0) {
        log.push(0);
        // Trigger update inside effect
        count = 1;
      } else {
        log.push(1);
      }
    };

    effect();
    expect(log).toEqual([0]);

    // Clear log
    log.length = 0;

    // This should not cause an infinite loop
    flushSync();
    expect(log).toEqual([1]);
  });

  it('should properly handle nested flushSync calls', () => {
    const log = [];
    let outer = 0;
    let inner = 0;

    const outerEffect = () => {
      log.push(`outer:${outer}`);
      if (outer === 0) {
        outer = 1;
      }
    };

    const innerEffect = () => {
      log.push(`inner:${inner}`);
      if (inner === 0) {
        inner = 1;
      }
    };

    outerEffect();
    expect(log).toEqual(['outer:0']);

    log.length = 0;

    // This should process both effects properly
    flushSync();
    expect(log).toContain('outer:1');
  });
});

