import { flushSync } from 'svelte';
import { test } from '../../test';

export default test({
	async test({ assert, target, logs }) {
		// This test reproduces the bug described in the issue:
		// flushSync() not properly executing $effect runes during testing

		const button = target.querySelector('button');

		// Initial state: count should be 0, log should be empty
		assert.equal(target.querySelector('p').textContent, 'Count: 0');
		assert.deepEqual(logs, []);

		// Click the button to increment count
		button.click();

		// Use flushSync to execute pending effects synchronously
		flushSync();

		// After flushSync, the count should be 1 and the effect should have logged
		assert.equal(target.querySelector('p').textContent, 'Count: 1');
		assert.deepEqual(logs, [1]);
	}
});

